var generate = function(numRows) {
    const rows = [];
    for (let r = 0; r < numRows; r++) {
        const row = new Array(r + 1).fill(1);
        for (let j = 1; j < r; j++) {
            row[j] = rows[r - 1][j - 1] + rows[r - 1][j];
        }
        rows.push(row);
    }
    return rows;
};
